// Final Production Audit — open each record directly from live Supabase database
const SUPABASE_URL = 'https://kvclcdjmjghndxsngfzb.supabase.co';
const SERVICE_ROLE_KEY = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6Imt2Y2xjZGptamdobmR4c25nZnpiIiwicm9sZSI6InNlcnZpY2Vfcm9sZSIsImlhdCI6MTc3MzE5NDAyNywiZXhwIjoyMDg4NzcwMDI3fQ.TaTRyViK-8sv3R_g1Me08sEjnyMskGXKF0u-I-PTaQ8';

const headers = {
  'apikey': SERVICE_ROLE_KEY,
  'Authorization': `Bearer ${SERVICE_ROLE_KEY}`,
  'Content-Type': 'application/json'
};

async function fetchRecord(table, id, idColumn = 'id') {
  const url = `${SUPABASE_URL}/rest/v1/${table}?${idColumn}=eq.${id}&limit=1`;
  const res = await fetch(url, { headers });
  const status = res.status;
  const body = await res.json();
  return { table, idColumn, id, http: status, found: Array.isArray(body) && body.length > 0, record: Array.isArray(body) && body.length > 0 ? body[0] : null };
}

async function countAll(table) {
  const url = `${SUPABASE_URL}/rest/v1/${table}?select=id&limit=1000`;
  const res = await fetch(url, { headers });
  const body = await res.json();
  return Array.isArray(body) ? body.length : 0;
}

// Also check live backend health/version
async function probeBackend() {
  const urls = ['https://ivx-api.onrender.com/health', 'https://api.ivxholding.com/health', 'https://ivx-api.onrender.com/version'];
  const results = {};
  for (const u of urls) {
    try {
      const res = await fetch(u, { signal: AbortSignal.timeout(15000) });
      results[u] = { status: res.status, body: await res.text() };
    } catch (e) {
      results[u] = { error: String(e) };
    }
  }
  return results;
}

const records = [
  { label: '1_waitlist', table: 'waitlist', id: '1a6ed87e-fc9c-4cc2-bd37-32798b85951c' },
  { label: '2_member', table: 'members', id: '14a484e0-dc93-49fd-b11a-72dec500a96c', idColumn: 'member_id' },
  { label: '3_investor_crm', table: 'investors', id: '403c322b-8610-40af-9876-3f77ee96b3a1' },
  { label: '4_analytics_event', table: 'analytics_events', id: '106636ae-67a6-4796-be4e-8223f87c3dbe' },
  { label: '5a_email_job_1', table: 'notifications', id: 'notif-f2c6b367-266b-4d92-9d45-18c582336da7' },
  { label: '5b_sms_job', table: 'sms_messages', id: '5b691141-2fc6-4575-8ab3-fe059e754bd3' },
  { label: '5c_email_job_2', table: 'notifications', id: 'notif-a910238b-b2d6-4d33-a56e-bd183ddd5d21' },
  { label: '6_audit_log', table: 'ivx_intent_audit', id: 'f240e5d3-c9e9-47b2-b835-eccbcc315467' },
  { label: '7_keyword', table: 'ivx_intent_keywords', id: '7dbc4529-0d51-4b60-9091-1ddd14cffe88' },
  { label: '8_visitor_intelligence', table: 'ivx_visitor_intelligence', id: 'd2e9b4da-bbf1-467f-a213-21d533e7bb6d' },
];

const verification = {};
for (const r of records) {
  try {
    verification[r.label] = await fetchRecord(r.table, r.id, r.idColumn || 'id');
  } catch (e) {
    verification[r.label] = { ...r, error: String(e) };
  }
}

// Dashboard counts (after)
const counts = {};
for (const t of ['waitlist', 'members', 'investors', 'analytics_events', 'notifications', 'sms_messages', 'ivx_intent_keywords', 'ivx_visitor_intelligence', 'ivx_intent_audit']) {
  try { counts[t] = await countAll(t); } catch (e) { counts[t] = `error: ${e}`; }
}

const backend = await probeBackend();

const output = {
  proof_type: 'ivx-final-production-audit-direct-record-verification-live',
  generated_at: new Date().toISOString(),
  supabase_url: SUPABASE_URL,
  visitor_email: 'visitor1783361815332@gmail.com',
  visitor_name: 'John Visitor',
  visitor_search_query: 'miami investment property for sale',
  visitor_landing_page: 'invest-miami',
  backend_probe: backend,
  records: verification,
  dashboard_counts_after: counts,
  dashboard_counts_before_from_previous_proof: {
    waitlist_total: 2,
    members_total: 5,
    investors_total: 880,
    analytics_events_total: 32,
    notifications_total: 4,
    sms_messages_total: 2,
    intent_keywords_total: 156,
    visitor_intelligence_total: 3,
    intent_audit_total: 2
  },
  github_sha: '2596b9fe7fb237064ead19ec2ffd36f0a7422146',
  render_deploy_id: 'dep-d95uhrei6hrs73fvi5tg'
};

console.log(JSON.stringify(output, null, 2));

